body:
The code example performs the following tasks:

- Imports `mongodb`, MongoDB's Node.js driver.

- Creates an instance of the `MongoClient` class to establish a
  connection to your cluster.

- The query uses the following pipeline stages:

  - [$search](pipe.$search) to search the `title` field
    using the `should` clause with the [wildcard](wildcard-ref) operator to
    search for titles that begin with `Prance` and `Prince`.
    The query also specifies that results must be sorted by the `title`
    field in ascending order.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `5` results.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Exclude all fields except `title`.

    - Add a field named `score`.

- Iterates over the cursor to print the documents that match the
  query.

**Input:**

```javascript
const { MongoClient } = require("mongodb");

// Replace the uri string with your MongoDB deployments connection string.
const uri =
  "<connection-string>";

const client = new MongoClient(uri);

async function run() {
  try {
    await client.connect();

    // set namespace
    const database = client.db("sample_mflix");
    const coll = database.collection("movies");

    // define pipeline
    const agg = [
      {
        '$search': {
          'compound': {
            'should': [
              {
                'wildcard': {
                  'query': [
                    'Prance*'
                  ], 
                  'path': 'title', 
                  'allowAnalyzedField': true
                }
              }, {
                'wildcard': {
                  'query': [
                    'Prince*'
                  ], 
                  'path': 'title', 
                  'allowAnalyzedField': true
                }
              }
            ]
          }, 
          'sort': { 'title': 1 }
        }
      }, {
        '$limit': 5
      }, {
        '$project': {'_id': 0, 'title': 1, 'score': {'$meta': 'searchScore'}
        }
      }
    ];

    // run pipeline
    const result = await coll.aggregate(agg);

    // print results
    await result.forEach((doc) => console.log(doc));

  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```

**Output:**

```javascript
{ title: 'Prancer', score: 1 }
{ title: 'Prancer Returns', score: 1 }
{ title: 'Prince', score: 1 }
{ title: 'Prince Avalanche', score: 1 }
{ title: 'Prince of Broadway', score: 1 }
```

